import{_ as e,c as d,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"バージョン履歴: 機能の進化 | opencode-agent-skills","description":"OpenCode Agent Skills プラグインのバージョン進化の歴史を学びます。本チュートリアルでは、v0.1.0 から v0.6.4 までのすべての主要な機能更新、バグ修正、アーキテクチャの改善、および重大な変更についてまとめています。","frontmatter":{"title":"バージョン履歴: 機能の進化 | opencode-agent-skills","sidebarTitle":"新バージョンの変更点","subtitle":"バージョン履歴","description":"OpenCode Agent Skills プラグインのバージョン進化の歴史を学びます。本チュートリアルでは、v0.1.0 から v0.6.4 までのすべての主要な機能更新、バグ修正、アーキテクチャの改善、および重大な変更についてまとめています。","tags":["バージョン更新","changelog","リリース履歴"],"order":3},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),l={name:"ja/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(i,t,s,n,c,h){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="バージョン履歴" tabindex="-1">バージョン履歴 <a class="header-anchor" href="#バージョン履歴" aria-label="Permalink to &quot;バージョン履歴&quot;">​</a></h1><p>本文書は OpenCode Agent Skills プラグインのすべてのバージョン更新を記録しています。バージョン履歴を通じて、機能の進化パス、修正された問題、およびアーキテクチャの改善を知ることができます。</p><div class="tip custom-block"><p class="custom-block-title">現在のバージョン</p><p>最新の安定版は <strong>v0.6.4</strong> (2026-01-20) です</p></div><h2 id="バージョンタイムライン" tabindex="-1">バージョンタイムライン <a class="header-anchor" href="#バージョンタイムライン" aria-label="Permalink to &quot;バージョンタイムライン&quot;">​</a></h2><table tabindex="0"><thead><tr><th>バージョン</th><th>リリース日</th><th>タイプ</th><th>主な内容</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>修正</td><td>YAML 解析、Claude v2 対応</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>改善</td><td>スキル推奨プロンプトの最適化</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>修正</td><td>スキル名とディレクトリ名の分離</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>改善</td><td>既読スキルの重複推奨を回避</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>新機能</td><td>セマンティックマッチング、embedding 事前計算</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>改善</td><td>あいまいマッチング提案、リファクタリング</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>改善</td><td>インストール方法の簡素化</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>改善</td><td>スクリプトの再帰検索</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>修正</td><td>シンボリックリンク処理</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>修正</td><td>エージェントモードの保持</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>修正</td><td>モデル切り替え問題</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>新機能</td><td>ファイルリスト機能</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>新機能</td><td>Superpowers モード</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>初期</td><td>4 つのツール、複数位置検出</td></tr></tbody></table><h2 id="詳細な変更履歴" tabindex="-1">詳細な変更履歴 <a class="header-anchor" href="#詳細な変更履歴" aria-label="Permalink to &quot;詳細な変更履歴&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>スキルの複数行説明の YAML frontmatter 解析を修正（<code>|</code> および <code>&gt;</code> ブロックスカラー構文をサポート）、カスタム解析器を <code>yaml</code> ライブラリに置き換えることで実現</li><li>Claude プラグイン v2 形式のサポートを追加、<code>installed_plugins.json</code> は単一オブジェクトではなくプラグインインストール配列を使用するようになりました</li></ul><p><strong>改善</strong>：</p><ul><li>Claude Code プラグインキャッシュ検出が新しいネストされたディレクトリ構造（<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>）をサポートするようになりました</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>改善</strong>：</p><ul><li>スキル評価プロンプトを最適化し、モデルがユーザーに「スキル不要」クラスのメッセージを送信するのを防止（ユーザーは非表示の評価プロンプトを見ることができません）</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>スキル検証で、ディレクトリ名と SKILL.md frontmatter の <code>name</code> が異なることを許可するようになりました。frontmatter の <code>name</code> は標準識別子であり、ディレクトリ名は組織化のみに使用されます。これは Anthropic Agent Skills 仕様に準拠しています。</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>改善</strong>：</p><ul><li>動的スキル推奨が各セッションで読み込まれたスキルを追跡するようになり、既読スキルの重複推奨を回避し、冗長なプロンプトとコンテキスト使用を削減します</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>新規追加</strong>：</p><ul><li><strong>セマンティックスキルマッチング</strong>：初期スキルリスト注入後、後続のメッセージはローカル embedding を使用してスキル説明とマッチングされます</li><li>ローカル embedding 生成用に <code>@huggingface/transformers</code> 依存関係を追加（量子化版 all-MiniLM-L6-v2）</li><li>メッセージが利用可能なスキルとマッチングした場合、3 ステップ評価プロンプト（EVALUATE → DECIDE → ACTIVATE）を注入し、スキルの読み込みを促進（<a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a> の<a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">ブログ記事</a>から着想）</li><li>低レイテンシーマッチングのためのディスクキャッシュ embedding（~/.cache/opencode-agent-skills/）</li><li><code>session.deleted</code> イベントでのセッションクリーンアップ</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>新規追加</strong>：</p><ul><li>すべてのツール（<code>use_skill</code>、<code>read_skill_file</code>、<code>run_skill_script</code>、<code>get_available_skills</code>）に「もしかして...」あいまいマッチング提案を追加</li></ul><p><strong>改善</strong>：</p><ul><li><strong>破壊的変更</strong>：<code>find_skills</code> ツールを <code>get_available_skills</code> に名前変更し、意図をより明確に</li><li><strong>内部</strong>：コードベースを独立したモジュール（<code>claude.ts</code>、<code>skills.ts</code>、<code>tools.ts</code>、<code>utils.ts</code>、<code>superpowers.ts</code>）に再編成し、保守性を向上</li><li><strong>内部</strong>：AI 生成のコメントと不要なコードを削除し、コード品質を向上</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>改善</strong>：</p><ul><li>インストール方法が OpenCode config 経由の npm パッケージを使用するようになり、git clone + シンボリックリンクではなくなりました</li></ul><p><strong>削除</strong>：</p><ul><li><code>INSTALL.md</code> を削除（簡素化されたインストール後に不要）</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>改善</strong>：</p><ul><li>スクリプト検出がスキルディレクトリ全体を再帰的に検索するようになりました（最大深度 10）、ルートディレクトリと <code>scripts/</code> サブディレクトリのみではなく</li><li>スクリプトは相対パス（例：<code>tools/build.sh</code>）で識別されるようになり、基本名ではなくなりました</li><li><code>read_skill_file</code>、<code>run_skill_script</code>、および <code>use_skill</code> ツールで <code>skill_name</code> パラメータを <code>skill</code> に名前変更</li><li><code>run_skill_script</code> ツールで <code>script_name</code> パラメータを <code>script</code> に名前変更</li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li><code>fs.stat</code> を使用してファイルとディレクトリの検出を修正し、シンボリックリンクを正しく処理</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>セッション開始時に合成メッセージを注入する際にエージェントモードを保持</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li><code>noReply</code> 操作中に現在のモデルを明示的に渡すことで、スキルツール使用時の予期しないモデル切り替えを修正（opencode issue #4475 への暫定対応）</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>新規追加</strong>：</p><ul><li><code>use_skill</code> 出力にファイルリストを追加</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>新規追加</strong>：</p><ul><li>Superpowers モードサポートを追加</li><li>リリース証明を追加</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>新規追加</strong>：</p><ul><li>スキルコンテンツをコンテキストに読み込む <code>use_skill</code> ツールを追加</li><li>スキルディレクトリ内のサポートファイルを読み取る <code>read_skill_file</code> ツールを追加</li><li>スキルディレクトリからスクリプトを実行する <code>run_skill_script</code> ツールを追加</li><li>利用可能なスキルを検索・一覧表示する <code>find_skills</code> ツールを追加</li><li>複数位置スキル検出を追加（プロジェクトレベル、ユーザーレベル、および Claude 互換位置）</li><li>Anthropic Agent Skills Spec v1.0 に準拠した frontmatter 検証を追加</li><li>セッション開始時およびコンテキスト圧縮後の自動スキルリスト注入を追加</li></ul><p><strong>新規コントリビューター</strong>：</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (メンテナー)</li></ul><h2 id="機能の進化の概要" tabindex="-1">機能の進化の概要 <a class="header-anchor" href="#機能の進化の概要" aria-label="Permalink to &quot;機能の進化の概要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>導入バージョン</th><th>進化パス</th></tr></thead><tbody><tr><td>4 つの基本ツール</td><td>v0.1.0</td><td>v0.5.0 であいまいマッチングを追加</td></tr><tr><td>複数位置スキル検出</td><td>v0.1.0</td><td>v0.4.1 でインストールを簡素化、v0.6.4 で Claude v2 をサポート</td></tr><tr><td>コンテキスト自動注入</td><td>v0.1.0</td><td>v0.3.0 でファイルリストを追加、v0.6.1 で重複推奨を回避</td></tr><tr><td>Superpowers モード</td><td>v0.2.0</td><td>継続的に安定</td></tr><tr><td>スクリプト再帰検索</td><td>v0.4.0</td><td>v0.3.3 でシンボリックリンクを修正</td></tr><tr><td>セマンティックマッチング推奨</td><td>v0.6.0</td><td>v0.6.1 で重複を回避、v0.6.3 でプロンプトを最適化</td></tr><tr><td>あいまいマッチング提案</td><td>v0.5.0</td><td>継続的に安定</td></tr></tbody></table><h2 id="重大な変更の説明" tabindex="-1">重大な変更の説明 <a class="header-anchor" href="#重大な変更の説明" aria-label="Permalink to &quot;重大な変更の説明&quot;">​</a></h2><h3 id="v0-6-0-セマンティックマッチング機能" tabindex="-1">v0.6.0：セマンティックマッチング機能 <a class="header-anchor" href="#v0-6-0-セマンティックマッチング機能" aria-label="Permalink to &quot;v0.6.0：セマンティックマッチング機能&quot;">​</a></h3><p>ローカル embedding ベースのセマンティックマッチング機能を導入し、AI がユーザーメッセージの内容に基づいて関連スキルを自動的に推奨できるようになり、ユーザーがスキル名を手動で記憶する必要がなくなりました。</p><ul><li><strong>技術的詳細</strong>：HuggingFace の <code>all-MiniLM-L6-v2</code> モデル（q8 量子化）を使用</li><li><strong>キャッシュメカニズム</strong>：embedding 結果を <code>~/.cache/opencode-agent-skills/</code> にキャッシュし、後続のマッチング速度を向上</li><li><strong>マッチングフロー</strong>：ユーザーメッセージ → embedding → スキル説明とのコサイン類似度計算 → Top 5 推奨（閾値 0.35）</li></ul><h3 id="v0-5-0-リファクタリングとツール名変更" tabindex="-1">v0.5.0：リファクタリングとツール名変更 <a class="header-anchor" href="#v0-5-0-リファクタリングとツール名変更" aria-label="Permalink to &quot;v0.5.0：リファクタリングとツール名変更&quot;">​</a></h3><p>コードアーキテクチャをモジュール化設計にリファクタリングし、ツール名をより明確にしました：</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-スクリプト検出メカニズムのアップグレード" tabindex="-1">v0.4.0：スクリプト検出メカニズムのアップグレード <a class="header-anchor" href="#v0-4-0-スクリプト検出メカニズムのアップグレード" aria-label="Permalink to &quot;v0.4.0：スクリプト検出メカニズムのアップグレード&quot;">​</a></h3><p>スクリプト検出を「ルートディレクトリ + scripts/ のみ」から「スキルディレクトリ全体の再帰検索」（最大深度 10）にアップグレードし、より柔軟なスクリプト組織化をサポートします。</p><h3 id="v0-2-0-superpowers-統合" tabindex="-1">v0.2.0：Superpowers 統合 <a class="header-anchor" href="#v0-2-0-superpowers-統合" aria-label="Permalink to &quot;v0.2.0：Superpowers 統合&quot;">​</a></h3><p>Superpowers ワークフローモードのサポートを追加し、<code>using-superpowers</code> スキルのインストールと環境変数 <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code> の設定が必要です。</p><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの位置を表示</strong></summary><blockquote><p>更新日時：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>現在のバージョン番号</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>バージョン履歴</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>主要バージョン情報</strong>：</p><ul><li><code>v0.6.4</code>：現在のバージョン (2026-01-20)</li><li><code>v0.6.0</code>：セマンティックマッチング導入 (2025-12-12)</li><li><code>v0.5.0</code>：リファクタリングバージョン (2025-12-11)</li><li><code>v0.1.0</code>：初期バージョン (2025-11-26)</li></ul></details>',72)])])}const v=e(l,[["render",r]]);export{p as __pageData,v as default};
